import{_ as t,o as e,c as i,O as r}from"./chunks/framework.bdcb0ee1.js";const p=JSON.parse('{"title":"Directory Listing","description":"","frontmatter":{},"headers":[],"relativePath":"administration/forumspark/directory-listing.md","filePath":"administration/forumspark/directory-listing.md","lastUpdated":1773167032000}'),o={name:"administration/forumspark/directory-listing.md"},a=r('<h1 id="directory-listing" tabindex="-1">Directory Listing <a class="header-anchor" href="#directory-listing" aria-label="Permalink to &quot;Directory Listing&quot;">​</a></h1><p>The ForumSpark Directory is a public listing of community forums. Listing your board in the directory helps new members discover your community.</p><p>You can manage your directory listing from the <strong>ForumSpark</strong> section in the Admin Control Panel.</p><nav class="table-of-contents"><ul><li><a href="#opting-in">Opting In</a></li><li><a href="#categories">Categories</a></li><li><a href="#screenshots">Screenshots</a></li><li><a href="#notes">Notes</a></li></ul></nav><h2 id="opting-in" tabindex="-1">Opting In <a class="header-anchor" href="#opting-in" aria-label="Permalink to &quot;Opting In&quot;">​</a></h2><p>By default, your board is not listed in the directory. To opt in:</p><ol><li>Go to <strong>ForumSpark &gt; Directory Listing</strong> in the Admin CP.</li><li>Toggle <strong>Listed in Directory</strong> to on.</li><li>Select a <strong>Category</strong> that best describes your community.</li><li>Write a short <strong>Description</strong> (max 500 characters) to help visitors understand what your forum is about.</li><li>Save your changes.</li></ol><img width="1933" height="1462" alt="image" src="https://github.com/user-attachments/assets/8eea2508-b9e2-4a39-8e37-f0c8fb2304ea"><h2 id="categories" tabindex="-1">Categories <a class="header-anchor" href="#categories" aria-label="Permalink to &quot;Categories&quot;">​</a></h2><p>Choose the category that best fits your forum:</p><table><thead><tr><th>Category</th><th></th></tr></thead><tbody><tr><td>Gaming</td><td>Technology</td></tr><tr><td>Creative &amp; Art</td><td>Music</td></tr><tr><td>Sports</td><td>Education</td></tr><tr><td>Entertainment</td><td>Science</td></tr><tr><td>Business</td><td>Lifestyle</td></tr><tr><td>Other</td><td></td></tr></tbody></table><p>You can change your category at any time.</p><h2 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h2><p>When your board is listed in the directory, a screenshot of your forum homepage is automatically captured and displayed alongside your listing. This gives potential members a preview of your community.</p><p>You can request a new screenshot at any time from the directory settings page. This is useful if you&#39;ve recently changed your theme or layout and want the listing to reflect the update.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Only boards with an active directory listing will appear in the public directory.</li><li>The description field supports plain text only (no BBCode or HTML).</li><li>Changes to your listing are synced to the directory when you save.</li><li>You can opt out of the directory at any time by toggling the listing off.</li></ul>',17),s=[a];function n(l,d,c,h,u,g){return e(),i("div",null,s)}const m=t(o,[["render",n]]);export{p as __pageData,m as default};
